function getDropdownOptions() 
{
  const ss = SpreadsheetApp.getActiveSpreadsheet();

  // Function to safely get values from a range in another sheet
  const getValuesFromRange = (rangeConfig) => 
  {
    try {
      const sheet = ss.getSheetByName(rangeConfig.sheet);
      if (!sheet) {
        console.error(`Sheet not found: ${rangeConfig.sheet}`);
        return [];
      }

      const range = sheet.getRange(rangeConfig.range);

      // Get values and filter out empty cells
      return range.getValues()
        .flat()
        .filter(value => value !== '' && value !== null && value !== undefined);
    } catch (error) {
      console.error(`Error getting values from ${rangeConfig.sheet}!${rangeConfig.range}: ${error}`);
      return [];
    }
};
  // Get values from all ranges
  const options = {
    projects: getValuesFromRange(CONFIG.RANGES.PROJECTS),
   // crewSizes: getValuesFromRange(CONFIG.RANGES.CREW_SIZES),
  //  timeSlots: getValuesFromRange(CONFIG.RANGES.TIME_SLOTS),
   // tasks: getValuesFromRange(CONFIG.RANGES.TASKS),
    owners: getValuesFromRange(CONFIG.RANGES.OWNERS)
  };

  // Log the options for debugging
  console.log('Dropdown options loaded:', options);

  return options;
}

/**
 * Validates that selected values exist in the allowed options
 */
function validateDropdownSelection(formData) {
  const options = getDropdownOptions();
  const errors = [];

  if (!options.projects.includes(formData.project)) {
    errors.push('Invalid project selection');
  }

  if (!options.crewSizes.includes(formData.crewSize)) {
    errors.push('Invalid crew size selection');
  }
  if (!options.timeSlots.includes(formData.timeSlot)) {
    errors.push('Invalid time slot selection');
  }
  if (!options.tasks.includes(formData.tasks)) {
    errors.push('Invalid task selection');
  }
  if (!options.owners.includes(formData.owner)) {
    errors.push('Invalid owner selection');
  }
  return {
    isValid: errors.length === 0,
    errors: errors
  };
}
/**
 * Adds a new booking to the sheet
 */
function addBooking(formData) {
  // Log the received data
  Logger.log('Received form data:', formData);

  try {
    // Validate the data
    if (!formData) {
      throw new Error('No booking data received');
    }

    // Validate required fields
    const requiredFields = ['project', 'crewSize', 'startTime', 'timeSlot', 'tasks', 'owner'];
    const missingFields = requiredFields.filter(field => !formData[field]);

    if (missingFields.length > 0) {
      throw new Error(`Missing required fields: ${missingFields.join(', ')}`);
    }

    // Get the sheet
    const sheet = SpreadsheetApp.getActiveSpreadsheet().getSheetByName(CONFIG.SHEET_NAME);
    if (!sheet) {
      throw new Error(`Sheet "${CONFIG.SHEET_NAME}" not found`);
    }

    // Find the next empty row
    const lastRow = sheet.getLastRow() + 1;

 // Remove the empty string at the start - data will now begin in column A
    const rowData = [
      formData.project,
      formData.crewSize,
      new Date(formData.startTime),
      formData.timeSlot,
      formData.tasks,
      formData.owner,
      formData.notes || '',
      ''  // Event ID
    ];


    // Log the data we're about to write
    Logger.log('Writing row data:', rowData);

    // Write to the sheet
    sheet.getRange(lastRow, 1, 1, rowData.length).setValues([rowData]);

    // Try to sync with calendar
    let syncResult = null;
    try {
      syncResult = syncWithCalendar();
    } catch (syncError) {
      Logger.log('Calendar sync error:', syncError);
      // Continue even if sync fails
    }

    return {
      success: true,
      message: 'Booking added successfully',
      syncResult: syncResult
    };

  } catch (error) {
    Logger.log('Error in addBooking:', error);
    return {
      success: false,
      message: error.message || 'Failed to add booking'
    };
  }
}

/**
 * Test function to verify booking functionality
 */
function testAddBooking() {
  const testData = {
    project: 'Test Project',
    crewSize: '1-2',
